// // This module implements a 16-bit DRAM cell with read and write functionality.
// Inputs include a 16-bit data line, a read enable (RE), a write enable (WE), and a clock (CLK).
// When WE is low, data should be written to the memory cell.
// When RE is low, the data stored in the memory cell should be output on a 16-bit data output line.
module dram_cell (  
    input [15:0] data_in,  
    input RE,  
    input WE,  
    input CLK,  
    output reg [15:0] data_out  
);  
    reg [15:0] memory;  

    always @(posedge CLK) begin  
        if (WE)  
            memory <= data_in;  
        if (RE)  
            data_out <= memory;  
    end  
endmodule

